CREATE TABLE IF NOT EXISTS permissions ( id integer NOT NULL , description character varying(255), name character varying(255) NOT NULL, CONSTRAINT permission_pkey PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS permission_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY permissions.id;
INSERT INTO permissions( id, name ,description) VALUES (nextval('permission_id_seq'), 'READ','Reads data');
INSERT INTO permissions( id, name ,description) VALUES (nextval('permission_id_seq'), 'ADD','Add data');
INSERT INTO permissions( id, name ,description) VALUES (nextval('permission_id_seq'), 'UPDATE','Update data');
CREATE TABLE IF NOT EXISTS role_permissions ( role_id integer NOT NULL, permission_id integer NOT NULL, CONSTRAINT role_permission_p_key PRIMARY KEY ( role_id , permission_id ), CONSTRAINT fk_role_id_20250318 FOREIGN KEY (role_id) REFERENCES role (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT fk_permission_id_20250318 FOREIGN KEY (permission_id) REFERENCES permissions (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION );
INSERT INTO role_permissions( role_id , permission_id ) VALUES (1, 1);
INSERT INTO role_permissions( role_id , permission_id ) VALUES (1, 2);
INSERT INTO role_permissions( role_id , permission_id ) VALUES (1, 3);
INSERT INTO role_permissions( role_id , permission_id ) VALUES (2, 1);
INSERT INTO role_permissions( role_id , permission_id ) VALUES (2 , 2);
